	// stays deferred and is retried.
	m.reconcileDeferred()
	if len(m.paths) != 1 || len(m.deferred) != 1 {
		t.Fatalf("reconcile before the address is assignable promoted a path: paths=%d deferred=%d", len(m.paths), len(m.deferred))
	}

